// Fires E2/E3/E4 on their calendar dates (Europe/Berlin). Any other day → no items → workflow ends.
// Source of truth for copy: marketing/emails/countdown-emails.json (keep in sync when editing).
const today = new Intl.DateTimeFormat('en-CA', { timeZone: 'Europe/Berlin' }).format(new Date());

const CTA = {
  en: 'https://schulab.com/register?utm_source=email&utm_medium=email&utm_campaign=earlyaccess_jun2026',
  de: 'https://schulab.com/de/register?utm_source=email&utm_medium=email&utm_campaign=earlyaccess_jun2026',
  ar: 'https://schulab.com/ar/register?utm_source=email&utm_medium=email&utm_campaign=earlyaccess_jun2026',
};

function layout(locale, heading, body, ctaLabel) {
  const dir = locale === 'ar' ? 'rtl' : 'ltr';
  const footer = {
    en: 'You receive this because you opted in to Schulab updates. Manage preferences: https://schulab.com/account',
    de: 'Du erhältst diese E-Mail, weil du Schulab-Updates abonniert hast. Einstellungen: https://schulab.com/de/account',
    ar: 'تصلك هذه الرسالة لأنك اشتركت في تحديثات Schulab. إدارة التفضيلات: https://schulab.com/ar/account',
  }[locale];
  return `<div dir="${dir}" style="font-family:Arial,Helvetica,sans-serif;max-width:560px;margin:0 auto;padding:24px;color:#0f172a">` +
    `<h1 style="font-size:22px;margin:0 0 16px">${heading}</h1>` +
    `<p style="font-size:15px;line-height:1.6;margin:0 0 24px">${body}</p>` +
    `<p style="margin:0 0 32px"><a href="${CTA[locale]}" style="background:#4f3ff0;color:#ffffff;padding:12px 24px;border-radius:10px;text-decoration:none;font-weight:bold">${ctaLabel}</a></p>` +
    `<p style="font-size:12px;color:#64748b;line-height:1.5">${footer}<br/>Impressum: https://schulab.com/impressum</p></div>`;
}

const EMAILS = {
  '2026-06-18': {
    id: 'E2',
    subject: { en: 'Your Schulab early access is open 🎉', de: 'Dein Schulab Early Access ist da 🎉', ar: 'وصولك المبكر إلى Schulab أصبح متاحًا 🎉' },
    html: {
      en: layout('en', 'Early access is open', 'Hi {{name}},<br/><br/>You are in the first group to experience Schulab: interactive STEM courses, live tutor sessions, badges and certificates — for ages 3–18, in English, German, and Arabic.<br/><br/>Everything is <b>free during early access</b>.', 'Start exploring'),
      de: layout('de', 'Der Early Access ist offen', 'Hallo {{name}},<br/><br/>du gehörst zur ersten Gruppe, die Schulab erlebt: interaktive MINT-Kurse, Live-Sessions mit Tutoren, Abzeichen und Zertifikate — für 3- bis 18-Jährige, auf Deutsch, Englisch und Arabisch.<br/><br/>Im Early Access ist alles <b>kostenlos</b>.', 'Jetzt entdecken'),
      ar: layout('ar', 'الوصول المبكر متاح الآن', 'مرحبًا {{name}}،<br/><br/>أنت ضمن المجموعة الأولى التي تجرّب Schulab: دورات STEM تفاعلية وجلسات مباشرة مع معلّمين وشارات وشهادات — للأعمار من ٣ إلى ١٨، بالعربية والإنجليزية والألمانية.<br/><br/>كل شيء <b>مجاني خلال فترة الوصول المبكر</b>.', 'ابدأ الاستكشاف'),
    },
  },
  '2026-06-24': {
    id: 'E3',
    subject: { en: 'Doors open tomorrow — Schulab launches June 25', de: 'Morgen geht’s los — Schulab startet am 25. Juni', ar: 'غدًا الانطلاق — Schulab تبدأ في ٢٥ يونيو' },
    html: {
      en: layout('en', 'Tomorrow is the day 🚀', 'Hi {{name}},<br/><br/>Schulab officially opens tomorrow, June 25. Interactive STEM, live tutors, certificates — free during early access. Log in early and pick your first course tonight.', 'Get a head start'),
      de: layout('de', 'Morgen ist es so weit 🚀', 'Hallo {{name}},<br/><br/>Schulab öffnet morgen, am 25. Juni, offiziell die Türen. Interaktives MINT-Lernen, Live-Tutoren, Zertifikate — im Early Access kostenlos. Logg dich schon heute ein und wähle deinen ersten Kurs.', 'Vorsprung sichern'),
      ar: layout('ar', 'غدًا هو اليوم المنتظر 🚀', 'مرحبًا {{name}}،<br/><br/>تفتح Schulab أبوابها رسميًا غدًا، ٢٥ يونيو. تعلّم STEM تفاعلي ومعلّمون مباشرون وشهادات — مجانًا خلال الوصول المبكر. سجّل دخولك الليلة واختر دورتك الأولى.', 'احجز مكانك'),
    },
  },
  '2026-06-25': {
    id: 'E4',
    subject: { en: 'Schulab is live — start learning free today 🚀', de: 'Schulab ist live — heute kostenlos starten 🚀', ar: 'انطلقت Schulab — ابدأ التعلم مجانًا اليوم 🚀' },
    html: {
      en: layout('en', 'We are live!', 'Hi {{name}},<br/><br/>Schulab is officially open. Jump into interactive STEM courses, book a live session with a tutor, and earn your first certificate — all free during early access.', 'Start learning now'),
      de: layout('de', 'Wir sind live!', 'Hallo {{name}},<br/><br/>Schulab ist offiziell gestartet. Stürz dich in interaktive MINT-Kurse, buche eine Live-Session mit einem Tutor und verdiene dein erstes Zertifikat — im Early Access alles kostenlos.', 'Jetzt lernen'),
      ar: layout('ar', 'انطلقنا!', 'مرحبًا {{name}}،<br/><br/>انطلقت Schulab رسميًا. انضم إلى دورات STEM التفاعلية واحجز جلسة مباشرة مع معلّم واحصل على شهادتك الأولى — كل ذلك مجانًا خلال الوصول المبكر.', 'ابدأ التعلم الآن'),
    },
  },
};

const email = EMAILS[today];
if (!email) { return []; }
return [{ json: email }];

// Pair each consented user with today's template in their locale (fallback en),
// personalise {{name}}, and emit a ready-to-send Resend request body per user.
const email = $('Pick Today Email').first().json;
const out = [];
for (const item of $input.all()) {
  const user = item.json;
  const locale = ['en', 'de', 'ar'].includes(user.locale) ? user.locale : 'en';
  const firstName = String(user.name || '').split(' ')[0] || 'there';
  out.push({
    json: {
      body: {
        from: 'Schulab <noreply@schulab.com>',
        to: [user.email],
        subject: email.subject[locale],
        html: email.html[locale].replaceAll('{{name}}', firstName),
      },
    },
  });
}
return out;
